/**
 * useThemedStyles Hook
 * Helper hook for creating StyleSheets with theme support
 *
 * Usage:
 * ```typescript
 * const createStyles = (theme: Theme) => StyleSheet.create({
 *   container: {
 *     backgroundColor: theme.colors.backgroundPrimary,
 *   }
 * });
 *
 * const Component = () => {
 *   const styles = useThemedStyles(createStyles);
 *   return <View style={styles.container} />;
 * };
 * ```
 */
import type { ImageStyle, TextStyle, ViewStyle } from 'react-native';
import type { Theme } from '../core/themes';
type NamedStyles<T> = {
    [P in keyof T]: ViewStyle | TextStyle | ImageStyle;
};
/**
 * Hook for creating themed styles
 * Returns memoized styles that update when theme changes
 */
export declare function useThemedStyles<T extends NamedStyles<T>>(createStyles: (theme: Theme) => T): T;
/**
 * Alternative: Direct StyleSheet creation with theme
 * Returns memoized styles that update when theme changes
 */
export declare function useThemedStyleSheet<T extends NamedStyles<T>>(styleFactory: (theme: Theme) => T): T;
export {};
